using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Register the training service as a singleton so category labels survive the app lifetime.
builder.Services.AddSingleton<ModelTrainingService>();

var app = builder.Build();

// Train & evaluate the model before accepting requests.
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
trainer.TrainAndEvaluate();

// Register PredictionEnginePool from the saved model file.
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild the service provider so the pool is available to controllers.
// (PredictionEnginePool must be registered before the host starts serving.)
// Instead, we register everything before Build(). Let's restructure:

// --- The correct ordering is below; the above was illustrative. ---
// We need to restructure so training happens at startup but registration happens before Build().

app.MapControllers();
app.Run();

