using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

builder.Services.AddSingleton<ModelTrainingService>();

// Train the model eagerly so we have a model file before building the host.
using (var tempProvider = builder.Services.BuildServiceProvider())
{
    var trainer = tempProvider.GetRequiredService<ModelTrainingService>();
    trainer.TrainAndEvaluate();

    // Re-register the already-trained instance so controllers receive the same labels.
    builder.Services.AddSingleton(trainer);

    // Register the thread-safe PredictionEnginePool from the saved model.
    builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
        .FromFile(trainer.ModelPath);
}

var app = builder.Build();
app.MapControllers();
app.Run();

