6. 
7. /// <summary>
8. /// Trains and evaluates the ticket classification model at startup.
9. /// </summary>
10. public class ModelTrainingService
11. {
12.     private readonly string _modelPath;
13.     private readonly string _dataPath;
14.     private readonly ILogger<ModelTrainingService> _logger;
15. 
16.     // Category labels in the order ML.NET assigns slot indices.
17.     public string[] CategoryLabels { get; private set; } = [];
18. 
19.     public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
20.     {
21.         _logger = logger;
22.         _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
23.         _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
24.     }
25. 
26.     public string ModelPath => _modelPath;
27. 
28.     public void TrainAndEvaluate()
29.     {
30.         var mlContext = new MLContext(seed: 42);
31. 
32.         // Load data
33.         IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
34.             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
35. 
36.         // Split: 80 % train / 20 % test
37.         var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
38. 
39.         // Build pipeline: featurise text + numeric → multi-class classification
40.         var pipeline = mlContext.Transforms.Conversion
41.                 .MapValueToKey("Label", nameof(TicketInput.Category))
42.             .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
43.             .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
44.             .Append(mlContext.Transforms.Concatenate("Features",
45.                 "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
46.             .Append(mlContext.Transforms.NormalizeMinMax("Features"))
47.             .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
48.                 labelColumnName: "Label", featureColumnName: "Features"))
49.             .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
50. 
51.         _logger.LogInformation("Training ticket classification model...");
52. 
53.         // Train
54.         var model = pipeline.Fit(split.TrainSet);
55. 
56.         // Evaluate on test set
57.         var predictions = model.Transform(split.TestSet);
58.         var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");
59. 
60.         _logger.LogInformation("=== Model Evaluation Metrics ===");
61.         _logger.LogInformation("Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
62.         _logger.LogInformation("Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
63.         _logger.LogInformation("Log Loss:          {LogLoss:F4}", metrics.LogLoss);
64.         _logger.LogInformation("Log Loss Reduction: {LogLossReduction:F4}", metrics.LogLossReduction);
65. 
66.         // Capture ordered category labels for confidence-score mapping
67.         var scoreColumn = predictions.Schema["Score"];
68.         var slotNames = new VBuffer<ReadOnlyMemory<char>>();
69.         scoreColumn.GetSlotNames(ref slotNames);
70.         CategoryLabels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
71. 
72.         _logger.LogInformation("Category labels: {Labels}", string.Join(", ", CategoryLabels));
73. 
74.         // Save model
75.         mlContext.Model.Save(model, data.Schema, _modelPath);
76.         _logger.LogInformation("Model saved to {Path}", _modelPath);
77.     }
78. }
